319	impl<'a, C: Consumer + ?Sized> PopIter<'a, C> {
320	    /// Create an iterator.
321	    pub fn new(inner: &'a mut C) -> Self {
322	        let (len, iter) = {
323	            let (left, right) = inner.occupied_slices();
324	            (left.len() + right.len(), left.iter().chain(right))
325	        };
326	        Self {
327	            inner,
328	            iter,
329	            count: 0,
330	            len,
331	        }
332	    }
